// Some portions generated by Codex
package org.eclipse.rdf4j.sail.lmdb;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.ArrayList;
import java.util.List;
import java.util.Set;

import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.algebra.Join;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.eclipse.rdf4j.query.algebra.Var;
import org.junit.jupiter.api.Test;

class LmdbLftjPlannerTest {

	private static final SimpleValueFactory VF = SimpleValueFactory.getInstance();
	private static final Set<String> CONFIGURED_INDEXES = Set.of("spoc", "sopc", "psoc", "posc", "ospc", "opsc");

	@Test
	void planShouldPrioritizeBoundVarsAnchorsAndLeafPredicatesForLargeQueries() {
		LmdbLftjPlanner planner = new LmdbLftjPlanner();
		List<StatementPattern> patterns = cycle5WithAnchoredLeaves();
		TupleExpr fallbackExpr = rebuildJoin(new ArrayList<>(patterns));

		LmdbLftjPlanner.PlanningResult result = planner.plan(fallbackExpr, patterns, CONFIGURED_INDEXES,
				List.of(
						new LmdbLftjPlan.OutputBinding("a", "a"),
						new LmdbLftjPlan.OutputBinding("aLabel", "aLabel"),
						new LmdbLftjPlan.OutputBinding("homepage", "homepage"),
						new LmdbLftjPlan.OutputBinding("mbox", "mbox")),
				completeInequalities(5),
				LmdbLftjPlanningHints.of(List.of("city"), List.of("aLabel", "mbox")));

		assertTrue(result.planned());
		List<String> variableOrder = result.plan().variableOrder();
		assertEquals(List.of("city", "a"), variableOrder.subList(0, 2));
		assertLeafVarsPrecedeCycleTail(variableOrder, List.of("mbox", "aLabel", "homepage"),
				List.of("b", "c", "d", "e"));
	}

	private List<StatementPattern> cycle5WithAnchoredLeaves() {
		return List.of(
				statementPattern("a", "knows", "b"),
				statementPattern("b", "knows", "c"),
				statementPattern("c", "knows", "d"),
				statementPattern("d", "knows", "e"),
				statementPattern("e", "knows", "a"),
				statementPattern("a", "basedNear", "city"),
				statementPattern("a", "label", "aLabel"),
				statementPattern("a", "mbox", "mbox"),
				statementPattern("a", "homepage", "homepage"));
	}

	private StatementPattern statementPattern(String subjectName, String predicateLocalName, String objectName) {
		return new StatementPattern(new Var(subjectName), new Var("p", VF.createIRI("urn:test:" + predicateLocalName)),
				new Var(objectName));
	}

	private TupleExpr rebuildJoin(List<StatementPattern> operands) {
		TupleExpr rebuilt = operands.get(0);
		for (int i = 1; i < operands.size(); i++) {
			rebuilt = new Join(rebuilt, operands.get(i));
		}
		return rebuilt;
	}

	private List<LmdbLftjPlan.InequalityConstraint> completeInequalities(int size) {
		List<LmdbLftjPlan.InequalityConstraint> inequalities = new ArrayList<>();
		for (int i = 0; i < size; i++) {
			for (int j = i + 1; j < size; j++) {
				inequalities.add(new LmdbLftjPlan.InequalityConstraint(variableName(i), variableName(j)));
			}
		}
		return inequalities;
	}

	private String variableName(int index) {
		return String.valueOf((char) ('a' + index));
	}

	private void assertLeafVarsPrecedeCycleTail(List<String> variableOrder, List<String> leafVars,
			List<String> cycleTail) {
		int latestLeafIndex = leafVars.stream()
				.mapToInt(variableOrder::indexOf)
				.max()
				.orElseThrow();
		int earliestCycleTailIndex = cycleTail.stream()
				.mapToInt(variableOrder::indexOf)
				.min()
				.orElseThrow();
		assertTrue(latestLeafIndex < earliestCycleTailIndex,
				() -> "expected leaf vars before cycle tail but got " + variableOrder);
	}
}
